const job = $input.first().json;

if (!job || !job.job_id) {
  return [{ json: { 
    status: 404, 
    body: { error: 'Job not found' } 
  }}];
}

if (job.status === 'IN_PROGRESS') {
  return [{ json: { 
    status: 200, 
    body: { status: 'IN_PROGRESS' } 
  }}];
}

// Status DONE, return semua data
return [{ json: { 
  status: 200, 
  body: { 
    status: 'DONE',
    data: {
      name: job.brand_summary,
      brand_summary: job.brand_summary,
      personality_and_tone: job.personality_and_tone,
      audience_and_values: job.audience_and_values,
      brand_promise: job.brand_promise,
      unique_selling_points: job.unique_selling_points,
      social_media_strategy: job.social_media_strategy,
      content_pillars: job.content_pillars,
      rules: job.rules,
      website_url: job.website_url,
      language: job.language
    }
  }
}}];

