const allReferences = $('Code in JavaScript').first().json;
const references = allReferences.references || [];

// grouping
const website = references
  .filter(r => r.platform === 'website' || r.type === 'website' || r.content_type === 'website')
  .map(r => r.link);

const instagram = references
  .filter(r => r.platform === 'instagram')
  .map(r => r.link);

const tiktok = references
  .filter(r => r.platform === 'tiktok')
  .map(r => r.link);

const youtube = references
  .filter(r => r.platform === 'youtube')
  .map(r => r.link);

const linkedin = references
  .filter(r => r.platform === 'linkedin')
  .map(r => r.link);

const facebook = references
  .filter(r => r.platform === 'facebook')
  .map(r => r.link);

const pdf = references
  .filter(r =>
    r.platform === 'pdf' ||
    r.type === 'pdf' ||
    r.content_type === 'pdf' ||
    r.link?.toLowerCase().includes('.pdf')
  )
  .map(r => r.link);

const image = references
  .filter(r =>
    r.platform === 'image' ||
    r.type === 'image' ||
    r.content_type === 'image'
  )
  .map(r => r.link);

return [{
  json: {
    website,
    instagram,
    tiktok,
    youtube,
    linkedin,
    facebook,
    pdf,
    image
  }
}];

const data = $('Code in JavaScript2').first().json;

const platforms = [
  'website',
  'instagram',
  'tiktok',
  'youtube',
  'linkedin',
  'facebook',
  'pdf',
  'image'
];

const allLinks = platforms.flatMap(platform =>
  (data[platform] || []).map(link => ({
    platform,
    link
  }))
);

return [{
  json: {
    references: allLinks
  }
}];
